# Tool: search for issues → returns URIs
@app.list_tools()
async def list_tools() -> list[types.Tool]:
    return [types.Tool(
        name="search_issues",
        description="Search GitHub issues and return their resource URIs",
        inputSchema={
            "type": "object",
            "properties": {
                "owner": {"type": "string"},
                "repo": {"type": "string"},
                "query": {"type": "string"}
            },
            "required": ["owner", "repo", "query"]
        }
    )]

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == "search_issues":
        owner, repo, query = arguments["owner"], arguments["repo"], arguments["query"]
        async with httpx.AsyncClient() as client:
            r = await client.get(
                "https://api.github.com/search/issues",
                params={"q": f"{query} repo:{owner}/{repo}"},
                headers={"Authorization": f"Bearer {os.environ['GITHUB_TOKEN']}"}
            )
            r.raise_for_status()
        items = r.json()["items"]
        # Return resource URIs the model can pass to resources/read
        uris = [f"github://repos/{owner}/{repo}/issues/{item['number']}" for item in items[:10]]
        return [types.TextContent(type="text", text="\n".join(uris))]
